    vatLawRows: [['— EXEMPT (ch. 3) —','Outside the Act, no right to deduct input VAT'],['Health services (§ 3-2)','Exempt','Doctor, dentist, physiotherapy etc. — no VAT and no input deduction'],['Social services (§ 3-4)','Exempt','Child welfare, elderly care, substance abuse care etc.'],['Education (§ 3-5)','Exempt','Schools, courses, training — both public and private'],['Financial services (§ 3-6)','Exempt','Banking, insurance, securities trading — no VAT'],['Arts/culture – performance (§ 3-7)','Exempt','Concerts, theatre, dance — tickets are VAT-free'],['Sports – right to participate (§ 3-8)','Exempt','Gym, football pitch, swimming pool etc.'],['Public authority exercise (§ 3-9)','Exempt'],['Real property/letting (§ 3-11)','Exempt (exception in (2))','Letting of residential and commercial property is exempt — but voluntary registration is possible for commercial'],['Charities (§ 3-12)','Exempt (certain sales)','Flea markets, bazaars etc. from charitable organisations'],['Non-profit membership fees (§ 3-13)','Exempt'],['Gambling (§ 3-14)','Exempt'],['Funeral – ceremony (§ 3-15)','Exempt'],['Board fees (§ 3-17)','Exempt (subject to employer NI)','Board fees are exempt from VAT but employer national insurance contributions apply'],['Privately used goods (§ 3-19)','Exempt','Private individuals selling used items do not need to charge VAT'],['— ZERO-RATED (ch. 6) —','Covered by the Act, 0% output VAT, right to deduct input VAT'],['Newspapers (§ 6-1)','Zero-rated'],['Periodicals (§ 6-3)','Zero-rated (final paragraph)'],['Books (§ 6-4)','Zero-rated (final paragraph)'],['Household electricity Northern Norway (§ 6-6)','Zero-rated'],['Electric vehicles ≤300 000 kr (§ 6-8)','Zero-rated','Applies only to purchase amount up to 300 000 kr — above this 25% VAT is charged'],['Vessels ≥15m (§ 6-9)','Zero-rated'],['Aircraft for business (§ 6-10)','Zero-rated'],['Transfer of business (§ 6-14)','Zero-rated','When an entire business is sold as a going concern, VAT history transfers — no VAT on the sale'],['Export of goods (§ 6-21)','Zero-rated','Export abroad — 0% VAT but full input deduction'],['Export of services (§ 6-22)','Zero-rated'],['Transport to/from abroad (§ 6-28)','Zero-rated'],['— DEEMED SUPPLY (ch. 3 part II) —',''],['Withdrawal of goods (§ 3-21)','VAT applies','Taking goods from the business for personal use requires VAT calculation'],['Withdrawal of services for personal use (§ 3-22)','VAT applies'],['Meals/produce/entertainment (§ 3-23)','VAT applies'],['— IMPORTS (ch. 3 part III) —',''],['Imported goods (§ 3-29)','VAT applies','Import of goods — VAT is calculated at customs clearance'],['Remotely deliverable services (§ 3-30)','Reverse charge','If you buy digital services from abroad you calculate the VAT yourself']],
    vatDefRows: [['Turnover (a)','Supply of goods/services for consideration','If you exchange something for money it is turnover'],['Goods (b)','Physical objects, real property, electricity, water, gas, heating, cooling'],['Services (c)','Anything that can be traded and is not goods','Consulting, hairdressing, transport, repairs etc.'],['Taxable person (d)','Registered/required to register in the VAT Register','Businesses with turnover above 50 000 kr in 12 months'],['Output VAT (e)','Calculated and paid on turnover and withdrawals','VAT you add to the price and collect from the customer'],['Input VAT (f)','Incurred on purchases or imports','VAT you pay when you buy goods/services for the business'],['Exemption from the Act (g)','Turnover not covered by the Act → no input deduction','The business cannot deduct VAT on purchases related to exempt turnover'],['Zero-rating (h)','Covered by the Act, but 0% output VAT → full input deduction','Exports are zero-rated — you do not add VAT but can deduct input VAT'],['Remotely deliverable services (i)','Not tied to a specific physical location','IT services, online consulting, streaming etc.'],['Electronic services (j)','Remotely deliverable, provided over the internet, automated','Apps, e-books, streaming services, online courses']],
    vatDedRows: [['Main rule (§ 8-1)','Deduction for input VAT used in registered business','You get back VAT on everything you buy for use in the business'],['Mixed use (§ 8-2)','Proportional deduction based on estimated use','If something is used 60% for business and 40% privately, you get 60% deduction'],['No deduction: catering (§ 8-3 a)','','Food and drink for employees, clients etc.'],['No deduction: entertainment (§ 8-3 e)','','Client dinners, events for business associates'],['No deduction: gifts (§ 8-3 f)','Not of trivial value','Gifts above the trivial threshold do not qualify for deduction'],['No deduction: housing/welfare (§ 8-3 g)','Exception: staff canteens'],['Passenger vehicles (§ 8-4)','No deduction (exceptions: leasing, taxi, resale)','Company car does not give VAT deduction unless used for leasing or passenger transport'],['Payment via bank (§ 8-8)','Required for ≥10 000 kr','Cash payments over 10 000 kr do not give VAT deduction']],
    vatAdjRows: [['Capital asset – business assets (§ 9-1 a)','Input VAT ≥50 000 kr','Machinery, vehicles etc. with VAT above 50 000 kr'],['Capital asset – real property (§ 9-1 b)','Input VAT ≥100 000 kr','Buildings, structures etc. with VAT above 100 000 kr'],['Adjustment period – business assets (§ 9-4)','5 years','If use changes over the next 5 years the VAT deduction must be adjusted'],['Adjustment period – real property (§ 9-4)','10 years','If use changes over the next 10 years the VAT deduction must be adjusted']],
    vatCalcRows: [['Main rule (§ 4-1)','Consideration excluding VAT'],['Barter (§ 4-3)','Fair market value','In barter transactions, market price is used as the basis for VAT'],['Related parties (§ 4-4)','Not lower than fair market value','If you sell cheaply to your own company, VAT is calculated on market price'],['Loss on receivables (§ 4-7)','May correct finally lost receivable','The customer never pays — then you can reverse VAT you have remitted']],
    vatRegRows: [['Joint registration (§ 2-2)','≥85% ownership, joint liability','Group companies can be registered as one VAT entity'],['Voluntary registration – letting (§ 2-3)','Buildings/structures to VAT-registered tenant','Landlord gets VAT deduction on renovation/construction when tenant is VAT-registered'],['Pre-registration (§ 2-4)','Significant acquisitions before turnover','Newly started businesses can register before reaching 50 000 kr in turnover']],
