    vatSubjRows: [['— CONDITIONS DE BASE —','Trois choses doivent être satisfaites pour la responsabilité TVA'],['1. Activité commerciale','Vous devez exercer une activité commerciale — pas un hobby ou un emploi','§ 2-1(1)'],['2. Fourniture de biens/services','Il doit y avoir une transaction — livraison contre contrepartie (paiement)','§ 1-3(1)a'],['3. Seuil de chiffre d\'affaires','Chiffre d\'affaires dépassant 50 000 kr sur 12 mois','§ 2-1(1)'],['— QUI DOIT S\'ENREGISTRER ? —',''],['Entreprises au-dessus de 50 000 kr','Doivent s\'enregistrer au registre de la TVA','§ 2-1(1)'],['Organismes caritatifs','Seuil plus élevé : 140 000 kr','§ 2-1(1)'],['Événements sportifs','Seuil distinct : 3 000 000 kr','§ 2-1(1)'],['— CONCEPTS CLÉS —',''],['Qu\'est-ce qu\'une « activité commerciale » ?','Une activité indépendante, durable, de caractère économique et capable de générer un profit. Les hobbies et les commandes ponctuelles ne sont normalement pas une activité commerciale.'],['Qu\'est-ce que le « chiffre d\'affaires » ?','Fourniture de biens ou services contre contrepartie. Les dons, l\'indemnisation et les subventions ne sont normalement pas du chiffre d\'affaires.','§ 1-3(1)a'],['Qu\'est-ce qu\'un « assujetti » ?','Une entité enregistrée (ou tenue de s\'enregistrer) au registre de la TVA, tenue de calculer et de payer la TVA.','§ 1-3(1)d'],['Enregistrement volontaire ?','Les bailleurs de propriétés commerciales peuvent s\'enregistrer volontairement pour obtenir des déductions sur la TVA en amont.','§ 2-3']],
    vatSubjTitle:'Qui est assujetti à la TVA ?', vatSubjDesc:'Activité commerciale · Seuil de chiffre d\'affaires · Obligation d\'enregistrement',
