    salTitle:'Lønn etter skatt', salDesc:'Beregn nettoinntekt fra brutto årslønn.',
    lGross:'Brutto årslønn (kr)', lClass:'Skatteklasse', lReg:'Kommune/region', btnCalc:'Beregn →',
