    avsGroupOpts: ['a: 30% – آلات مكتبية إلخ','b: 20% – شهرة تجارية','c: 24% – شاحنات، حافلات إلخ','d: 20% – سيارات، آلات، معدات إلخ','e: 14% – سفن، قوارب، منصات إلخ','f: 12% – طائرات، مروحيات','g: 5% – معدات كهروتقنية في شركات الطاقة','h: 4% – مباني ومنشآت (حيوانية 6%، بسيطة 10%)','i: 2% – مباني تجارية','j: 10% – تركيبات تقنية ثابتة في المباني'],
