    vatSubjRows: [['— PAGRINDINĖS SĄLYGOS —','Trys dalykai turi būti įvykdyti PVM atsakomybei'],['1. Verslo veikla','Turite vykdyti verslo veiklą — ne hobį ar darbo santykį','§ 2-1(1)'],['2. Prekių/paslaugų tiekimas','Turi būti sandoris — tiekimas už atlygį (mokėjimas)','§ 1-3(1)a'],['3. Apyvartos riba','Apyvarta viršijanti 50 000 kr per 12 mėnesių','§ 2-1(1)'],['— KAS PRIVALO REGISTRUOTIS? —',''],['Verslo subjektai virš 50 000 kr','Privalo registruotis PVM registre','§ 2-1(1)'],['Labdaros org.','Aukštesnė riba: 140 000 kr','§ 2-1(1)'],['Sporto renginiai','Atskira riba: 3 000 000 kr','§ 2-1(1)'],['— PAGRINDINĖS SĄVOKOS —',''],['Kas yra « verslo veikla »?','Savarankiška, nuolatinė ekonominio pobūdžio veikla, galinti duoti pelno. Hobiai ir vienkarinės užduotys paprastai nėra verslas.'],['Kas yra « apyvarta »?','Prekių ar paslaugų tiekimas už atlygį. Dovanos, atlyginimas ir dotacijos paprastai nėra apyvarta.','§ 1-3(1)a'],['Kas yra « PVM subjektas »?','Subjektas, užsiregistravęs (arba turėtų būti užsiregistravęs) PVM registre, privalantis skaičiuoti ir mokėti PVM.','§ 1-3(1)d'],['Savanoriška registracija?','Komercinės paskirties nekilnojamojo turto savininkai gali savanoriškai registruotis, kad gautų įvestės PVM atskaitymą.','§ 2-3']],
