    vatDefRows: [['Apyvarta (a)','Prekių/paslaugų tiekimas už atlygį','Mainant ką nors už pinigus, tai yra apyvarta'],['Prekės (b)','Fiziniai daiktai, nekilnojamasis turtas, elektra, vanduo, dujos, šiluma, šaltis'],['Paslaugos (c)','Viskas, kas gali būti parduodama ir nėra prekės','Konsultacijos, kirpykla, transportas, remontas ir pan.'],['PVM subjektas (d)','Registruotas/privalantis registruotis PVM registre','Įmonės su apyvarta virš 50 000 kr per 12 mėnesių'],['Pardavimo PVM (e)','Skaičiuojamas ir mokamas pardavus ir paėmus','PVM, kurį pridedate prie kainos ir surenkate iš kliento'],['Pirkimo PVM (f)','Sumokėtas perkant ar importuojant','PVM, kurį mokate pirkdami prekes/paslaugas įmonei'],['Išimtis iš įstatymo (g)','Apyvarta nepatenka į įstatymą → be atskaitymo teisės','Įmonė negali atskaityti PVM už pirkimus, susijusius su neapmokestinama apyvarta'],['Atleidimas nuo PVM (h)','Patenka į įstatymą, bet 0% pardavimo PVM → pilna atskaitymo teisė','Eksportas atleistas — nepridedate PVM, bet galite atskaityti pirkimo PVM'],['Nuotolinės paslaugos (i)','Nesusietos su konkrečia fizine vieta','IT paslaugos, konsultacijos internetu, transliavimas ir pan.'],['Elektroninės paslaugos (j)','Nuotolinės, teikiamos internetu, automatizuotos','Programėlės, e. knygos, transliavimo paslaugos, internetiniai kursai']],
    vatDedRows: [['Pagrindinė taisyklė (§ 8-1)','Pirkimo PVM atskaitymas naudojimui registruotoje veikloje','Gaunate PVM grąžą už viską, ką perkate įmonės reikmėms'],['Mišrus naudojimas (§ 8-2)','Proporcinis atskaitymas pagal numatomą naudojimą','Jei naudojama 60% verslui ir 40% asmeniškai, gaunate 60% atskaitymą'],['Be atskaitymo: maitinimas (§ 8-3 a)','','Maistas ir gėrimai darbuotojams, klientams ir pan.'],['Be atskaitymo: reprezentacija (§ 8-3 e)','','Klientų vakarienės, renginiai verslo partneriams'],['Be atskaitymo: dovanos (§ 8-3 f)','Ne mažareikšmės vertės','Dovanos virš mažareikšmės ribos nesuteikia atskaitymo'],['Be atskaitymo: būstas/socialinė gerovė (§ 8-3 g)','Išimtis: įmonės valgyklos'],['Lengvasis automobilis (§ 8-4)','Be atskaitymo (išimtis: nuoma, taksi, pardavimas)','Tarnybinis automobilis nesuteikia PVM atskaitymo, nebent naudojamas nuomai ar keleivių pervežimui'],['Mokėjimas per banką (§ 8-8)','Reikalavimas esant ≥10 000 kr','Grynieji mokėjimai virš 10 000 kr nesuteikia PVM atskaitymo']],
