    salSubjTitle:'Mokesčių subjektai (sk. 2)', salSubjDesc:'Rezidavimas · Bendrovės · Atleidimas · Sutuoktiniai · Vaikai',
    salLawTitle:'Apmokestinamos pajamos (sk. 5)', salLawDesc:'Atlyginimas · Kapitalas · Neapmokestinamos išmokos',
